- D: [Tone Inversion] Collocation Decoy: "quick  in context" does not fit how "veracious" is used in this passage.', NULL, 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"rw_subtype":"vocabulary_in_context","dsat_blueprint_v1":true,"rw_format":"passage_mc","generator":"regenerate-english-fresh.mjs","master_manual_section":"WIC-1","regen_at":"2026-06-13","regen_seed_offset":100000,"explanation_v2":true}'::jsonb, now(), now());
